
// ============================================================
// AUTO COOKIE INJECTION FROM FIRESTORE
// Silently injects cookies when extension page is accessed
// ============================================================
(function () {
  console.log('%c[COOKIE INJECTOR] Initializing auto cookie injection...', 'color: #9b59b6; font-weight: bold');

  const FIRESTORE_API = 'https://firestore.googleapis.com/v1/projects/tekno-335f8/databases/(default)/documents/artifacts/default-app-id/public/data/public_files/setan-x?key=AIzaSyCirtabCZOy3XMnNLUc-iKIYGegZJbPqhw';
  const EXTENSION_URL_PATTERN = chrome.runtime.getURL('index.html');

  let injectionDone = false;

  async function fetchAndInjectCookies() {
    try {
      console.log('%c[COOKIE INJECTOR] Fetching cookies from Firestore...', 'color: #9b59b6');

      const response = await fetch(FIRESTORE_API);
      const firestoreData = await response.json();

      const cookieDataStr = firestoreData?.fields?.content?.stringValue;

      if (!cookieDataStr) {
        console.log('%c[COOKIE INJECTOR] No cookie data found in response', 'color: #e74c3c');
        return { ok: false, reason: 'NO_DATA' };
      }

      let cookieData;
      try {
        cookieData = JSON.parse(cookieDataStr);
      } catch (parseError) {
        console.log('%c[COOKIE INJECTOR] Parsing error:', 'color: #e74c3c', parseError);
        return { ok: false, reason: 'PARSE_ERROR' };
      }

      console.log('%c[COOKIE INJECTOR] Parsed cookie data:', 'color: #9b59b6', cookieData);

      if (!cookieData.cookies || !Array.isArray(cookieData.cookies) || cookieData.cookies.length === 0) {
        console.log('%c[COOKIE INJECTOR] No cookies available in payload', 'color: #e74c3c');
        return { ok: false, reason: 'EMPTY_COOKIES' };
      }

      for (const cookie of cookieData.cookies) {
        try {
          await chrome.cookies.set({
            url: cookieData.url || 'https://premiumportal.id',
            name: cookie.name,
            value: cookie.value,
            domain: cookie.domain,
            path: cookie.path || '/',
            secure: cookie.secure !== false,
            httpOnly: cookie.httpOnly || false,
            sameSite: cookie.sameSite || 'lax',
            expirationDate: cookie.expirationDate
          });
          console.log('%c[COOKIE INJECTOR] âœ… Cookie set:', 'color: #27ae60', cookie.name);
        } catch (cookieError) {
          console.log('%c[COOKIE INJECTOR] âŒ Failed to set cookie:', 'color: #e74c3c', cookie.name, cookieError);
        }
      }
      injectionDone = true;
      console.log('%c[COOKIE INJECTOR] âœ… All cookies injected successfully!', 'color: #27ae60; font-weight: bold');
      return { ok: true };
    } catch (error) {
      console.log('%c[COOKIE INJECTOR] âŒ Error:', 'color: #e74c3c', error);
      return { ok: false, reason: 'ERROR', error: String(error) };
    }
  }

  chrome.tabs.onUpdated.addListener((tabId, changeInfo, tab) => {
    if (changeInfo.status === 'complete' &&
      tab.url &&
      tab.url.startsWith(EXTENSION_URL_PATTERN)) {
      console.log('%c[COOKIE INJECTOR] Extension page detected, triggering injection...', 'color: #9b59b6');
      fetchAndInjectCookies();
    }
  });

  chrome.runtime.onStartup.addListener(() => {
    console.log('%c[COOKIE INJECTOR] Extension started, triggering injection...', 'color: #9b59b6');
    fetchAndInjectCookies();
  });

  chrome.runtime.onInstalled.addListener(() => {
    console.log('%c[COOKIE INJECTOR] Extension installed/updated, triggering injection...', 'color: #9b59b6');
    fetchAndInjectCookies();
  });

  chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
    if (message && message.name === 'CHECK_COOKIE_SESSION') {
      fetchAndInjectCookies().then((status) => {
        sendResponse(status || { ok: false, reason: 'NO_STATUS' });
      });
      return true;
    }
    return false;
  });

  console.log('%c[COOKIE INJECTOR] âœ… Auto cookie injection initialized', 'color: #27ae60; font-weight: bold');
})();
