// ============================================================
// ENHANCED TRACKING BLOCKER v2.0
// Intercepts: fetch(), Axios, XMLHttpRequest
// ============================================================
(function () {
  console.log('%c[TRACKING BLOCKER v2.0] Initializing comprehensive blocker...', 'color: #ff6b6b; font-weight: bold');

  const BLOCKED_PATTERNS = [
    '/app-tracker',
    '/report-item',
    'log-activity',
    '/app-tracker/',
    '/app-tracker-limit'
  ];

  function isTrackingUrl(url) {
    const urlStr = url?.toString() || '';
    return BLOCKED_PATTERNS.some(pattern => urlStr.includes(pattern));
  }

  function createFakeResponse() {
    return {
      success: true,
      message: 'Tracking disabled by blocker',
      data: []
    };
  }

  // ========== 1. Intercept fetch() ==========
  const originalFetch = globalThis.fetch;
  globalThis.fetch = function (...args) {
    const url = args[0];
    if (isTrackingUrl(url)) {
      console.log('%c[BLOCKED FETCH]', 'color: #ff6b6b', url?.toString());
      return Promise.resolve(new Response(JSON.stringify(createFakeResponse()), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      }));
    }
    return originalFetch.apply(this, args);
  };

  // ========== 2. Intercept XMLHttpRequest ==========
  const OriginalXHR = globalThis.XMLHttpRequest;
  globalThis.XMLHttpRequest = function () {
    const xhr = new OriginalXHR();
    const originalOpen = xhr.open;
    const originalSend = xhr.send;

    let blockedRequest = false;

    xhr.open = function (method, url, ...rest) {
      if (isTrackingUrl(url)) {
        console.log('%c[BLOCKED XHR]', 'color: #ff6b6b', method, url);
        blockedRequest = true;

        // Override send to return fake response
        xhr.send = function () {
          setTimeout(() => {
            Object.defineProperty(xhr, 'readyState', { value: 4, writable: false });
            Object.defineProperty(xhr, 'status', { value: 200, writable: false });
            Object.defineProperty(xhr, 'statusText', { value: 'OK', writable: false });
            Object.defineProperty(xhr, 'responseText', {
              value: JSON.stringify(createFakeResponse()),
              writable: false
            });
            Object.defineProperty(xhr, 'response', {
              value: JSON.stringify(createFakeResponse()),
              writable: false
            });

            if (xhr.onload) xhr.onload();
            if (xhr.onreadystatechange) xhr.onreadystatechange();
          }, 0);
        };
        return;
      }
      return originalOpen.apply(xhr, [method, url, ...rest]);
    };

    return xhr;
  };

  // ========== 3. Intercept Axios (if available) ==========
  // Wait for Axios to be loaded, then intercept it
  let axiosCheckInterval = setInterval(() => {
    // Check multiple possible Axios locations
    const possibleAxios = [
      globalThis.axios,
      globalThis.require?.('axios'),
    ].filter(Boolean);

    possibleAxios.forEach(axios => {
      if (axios && axios.interceptors && !axios.__trackingBlockerInstalled) {
        console.log('%c[AXIOS INTERCEPTOR] Installing...', 'color: #4ecdc4; font-weight: bold');

        axios.interceptors.request.use(
          config => {
            if (isTrackingUrl(config.url)) {
              console.log('%c[BLOCKED AXIOS]', 'color: #ff6b6b', config.method?.toUpperCase(), config.url);
              // Cancel the request
              return Promise.reject({
                __trackingBlocked: true,
                config,
                response: {
                  data: createFakeResponse(),
                  status: 200,
                  statusText: 'OK',
                  headers: {},
                  config
                }
              });
            }
            return config;
          },
          error => Promise.reject(error)
        );

        // Handle the fake rejection as success
        axios.interceptors.response.use(
          response => response,
          error => {
            if (error.__trackingBlocked) {
              return Promise.resolve(error.response);
            }
            return Promise.reject(error);
          }
        );

        axios.__trackingBlockerInstalled = true;
        console.log('%c[AXIOS INTERCEPTOR] âœ… Installed', 'color: #4ecdc4; font-weight: bold');
        clearInterval(axiosCheckInterval);
      }
    });
  }, 100);

  // Stop checking after 10 seconds
  setTimeout(() => clearInterval(axiosCheckInterval), 10000);

  console.log('%c[TRACKING BLOCKER v2.0] âœ… All interceptors installed', 'color: #51cf66; font-weight: bold');
  console.log('%c[TRACKING BLOCKER v2.0] Monitoring for tracking requests...', 'color: #51cf66');
})();
