// ============================================================
// ENHANCED STANDALONE MODE v2 - Complete Independence
// Overrides chrome.management API to prevent Premium Tools detection
// ============================================================
(function () {
  console.log('%c[STANDALONE v2] Initializing complete independence mode...', 'color: #4ecdc4; font-weight: bold');

  // 1. Force active state to always be true
  try {
    chrome.storage.local.set({ active: "true" });
    console.log('%c[STANDALONE v2] Set active="true" in storage', 'color: #4ecdc4');
  } catch (e) {
    console.error('[STANDALONE v2] Error setting storage:', e);
  }

  // 2. Override chrome.storage.local.get to always return active=true
  const originalStorageGet = chrome.storage.local.get.bind(chrome.storage.local);
  chrome.storage.local.get = function (keys) {
    return new Promise((resolve) => {
      originalStorageGet(keys).then((result) => {
        if (result && typeof result.active !== 'undefined') {
          console.log('%c[STANDALONE v2] Intercepted storage.get - forcing active="true"', 'color: #ffa94d');
          result.active = "true";
        }
        if (Array.isArray(keys) && keys.includes('active')) {
          result.active = "true";
        } else if (keys === 'active' || (typeof keys === 'object' && 'active' in keys)) {
          result.active = "true";
        }
        resolve(result);
      });
    });
  };

  // 3. Prevent storage.set from setting active to false
  const originalStorageSet = chrome.storage.local.set.bind(chrome.storage.local);
  chrome.storage.local.set = function (items) {
    if (items && items.active === "false") {
      console.log('%c[STANDALONE v2] Blocked attempt to set active="false"', 'color: #ff6b6b');
      items.active = "true";
    }
    return originalStorageSet(items);
  };

  // 4. Override chrome.management API completely
  if (chrome.management) {
    console.log('%c[STANDALONE v2] Overriding chrome.management API...', 'color: #4ecdc4');

    // Create a fake extension object for Premium Tools (appears as disabled but installed)
    const fakeExtension = {
      id: 'fake-premium-tools-id',
      name: 'Premium Tools Extension',
      enabled: false, // Pretend it's disabled (not uninstalled)
      version: '1.0.0',
      description: 'Fake Premium Tools (Standalone Mode)',
      type: 'extension'
    };

    // Override chrome.management.get
    const originalManagementGet = chrome.management.get.bind(chrome.management);
    chrome.management.get = function (id, callback) {
      console.log('%c[STANDALONE v2] Intercepted chrome.management.get(' + id + ')', 'color: #ffa94d');
      // Return fake extension if looking for Premium Tools
      if (callback) {
        setTimeout(() => callback(fakeExtension), 0);
      }
      return Promise.resolve(fakeExtension);
    };

    // Override chrome.management.getAll
    const originalGetAll = chrome.management.getAll ? chrome.management.getAll.bind(chrome.management) : null;
    if (originalGetAll) {
      chrome.management.getAll = function (callback) {
        console.log('%c[STANDALONE v2] Intercepted chrome.management.getAll()', 'color: #ffa94d');
        return originalGetAll((extensions) => {
          // Add fake Premium Tools to the list
          const modifiedList = [...extensions, fakeExtension];
          if (callback) callback(modifiedList);
          return modifiedList;
        });
      };
    }

    // Stub event listeners to prevent them from triggering
    const stubListener = {
      addListener: function (callback) {
        console.log('%c[STANDALONE v2] Suppressed management event listener', 'color: #ffa94d');
        // Don't actually register the listener
      },
      removeListener: function () { },
      hasListener: function () { return false; }
    };

    // Replace all management event listeners
    if (chrome.management.onInstalled) {
      const originalOnInstalled = chrome.management.onInstalled;
      chrome.management.onInstalled = stubListener;
    }

    if (chrome.management.onUninstalled) {
      chrome.management.onUninstalled = stubListener;
    }

    if (chrome.management.onEnabled) {
      chrome.management.onEnabled = stubListener;
    }

    if (chrome.management.onDisabled) {
      chrome.management.onDisabled = stubListener;
    }

    console.log('%c[STANDALONE v2] âœ… chrome.management API overridden', 'color: #51cf66');
  }

  console.log('%c[STANDALONE v2] âœ… Extension running in complete independence mode', 'color: #51cf66; font-weight: bold');
  console.log('%c[STANDALONE v2] Premium Tools Extension is NOT required (even if uninstalled)', 'color: #51cf66');
})();
